async (params, browser) => {
  // Open arXiv search
  await browser.open(`https://arxiv.org/search/?searchtype=all&query=${params.query}`)

  // Wait for results
  await browser.waitForSelector('li.arxiv-result, ol.breathe-horizontal', 15000)

  // Let results render
  await browser.wait(2000)

  // Extract papers
  const results = await browser.evaluate(`const results = []; document.querySelectorAll('li.arxiv-result').forEach((el, i) => { if (i < 15) { const titleEl = el.querySelector('p.title'); const authorsEl = el.querySelector('p.authors'); const abstractEl = el.querySelector('.abstract-full') || el.querySelector('.abstract-short'); const idEl = el.querySelector('.list-title a[href*="/abs/"]'); const catsEl = el.querySelector('.tags'); results.push({ title: titleEl?.textContent?.replace('Title:', '')?.trim() || '', authors: authorsEl?.textContent?.replace('Authors:', '')?.trim() || '', abstract: (abstractEl?.textContent?.trim()?.replace(/\s*(More|Less)\s*$/, '') || '').slice(0, 300), arxiv_id: idEl?.textContent?.trim() || '', url: idEl?.href || '', categories: catsEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return results
}
